class MyCircularDeque:

    def __init__(self, k: int):
        self._queue = [None] * k
        self._capacity = k
        self._front = 0
        self._rear = 0
        self._size = 0

    def insertFront(self, value: int) -> bool:
        if self.isFull():
            return False

        self._front = (self._front - 1 + self._capacity) % self._capacity
        self._queue[self._front] = value
        self._size += 1
        return True

    def insertLast(self, value: int) -> bool:
        if self.isFull():
            return False

        self._queue[self._rear] = value
        self._rear = (self._rear + 1) % self._capacity
        self._size += 1
        return True

    def deleteFront(self) -> bool:
        if self.isEmpty():
            return False

        self._queue[self._front] = None 
        self._front = (self._front + 1) % self._capacity
        self._size -= 1
        return True

    def deleteLast(self) -> bool:
        if self.isEmpty():
            return False

        self._rear = (self._rear - 1 + self._capacity) % self._capacity
        self._queue[self._rear] = None
        self._size -= 1
        return True

    def getFront(self) -> int:
        if self.isEmpty():
            return -1
        return self._queue[self._front]

    def getRear(self) -> int:
        if self.isEmpty():
            return -1
        return self._queue[(self._rear - 1 + self._capacity) % self._capacity]

    def isEmpty(self) -> bool:
        return self._size == 0

    def isFull(self) -> bool:
        return self._size == self._capacity
